            >
              {loading ? "Deploying..." : "Deploy Agent"}
            </button>
          </div>
        </div>
      )}

      {/* Deploy in progress / success */}
      {step === "deploy" && deployInfo && (
        <div className="mx-auto max-w-md">
          <h3 className="font-serif text-2xl text-ink">
            {deployStatus === "SUCCESS" ? "Agent deployed." : "Deploying..."}
