import { NextRequest, NextResponse } from "next/server";
import {
  createProject,
  createService,
  setEnvVarsForProject,
  createVolume,
  createDomain,
} from "@/lib/railway";

interface DeployRequest {
  agentName: string;
  veniceModel: string;
  spendingCap: string;
  dailyLimit: string;
  telegramBotToken?: string;
  telegramAllowedUsers?: string;
}

export async function POST(req: NextRequest) {
  const body: DeployRequest = await req.json();

  if (!body.agentName) {
    return NextResponse.json(
      { error: "Missing agent name" },
      { status: 400 }
    );
  }

  try {
    // 1. Create project (or reuse existing)
    let projectId = process.env.RAILWAY_PROJECT_ID;
    if (!projectId) {
      projectId = await createProject(`synthesis-${body.agentName}`);
    }

    // 2. Create service from GitHub repo
    const repo = process.env.RAILWAY_GITHUB_REPO || "builders-garden/synthesis-hack";
    const { serviceId, environmentId } = await createService(
      projectId,
      repo,
      "main",
      "apps/agent"
    );

    // 3. Set env vars
    const setupPassword = crypto.randomUUID().replace(/-/g, "").slice(0, 32);
    const envVars: Record<string, string> = {
      AGENT_NAME: body.agentName,
      SETUP_PASSWORD: setupPassword,
      VENICE_MODEL: body.veniceModel || "venice/llama-3.3-70b",
      SPENDING_CAP: body.spendingCap || "5",
      DAILY_LIMIT: body.dailyLimit || "10",
    };

    if (body.telegramBotToken) {
      envVars.TELEGRAM_BOT_TOKEN = body.telegramBotToken;
    }
    if (body.telegramAllowedUsers) {
      envVars.TELEGRAM_ALLOWED_USERS = body.telegramAllowedUsers;
    }

    await setEnvVarsForProject(projectId, serviceId, environmentId, envVars);

    // 4. Create persistent volume
    await createVolume(projectId, serviceId, environmentId, "/data");

    // 5. Generate public domain
    const domain = await createDomain(serviceId, environmentId);

    // 6. Deployment is triggered automatically when env vars and source are set.
    //    Railway auto-deploys on service creation with a linked repo.

    return NextResponse.json({
      projectId,
      serviceId,
      environmentId,
      domain: `https://${domain}`,
      setupPassword,
      status: "deploying",
    });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Deploy failed";
    console.error("Railway deploy error:", message);
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

