const RAILWAY_API = "https://backboard.railway.com/graphql/v2";

function getToken(): string {
  const token = process.env.RAILWAY_API_TOKEN;
  if (!token) throw new Error("RAILWAY_API_TOKEN is not set");
  return token;
}

async function gql<T>(query: string, variables?: Record<string, unknown>): Promise<T> {
  const res = await fetch(RAILWAY_API, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${getToken()}`,
    },
    body: JSON.stringify({ query, variables }),
  });

  const json = await res.json();
  if (json.errors) {
    throw new Error(json.errors.map((e: { message: string }) => e.message).join(", "));
  }
  return json.data as T;
}

export async function createProject(name: string): Promise<string> {
  const data = await gql<{ projectCreate: { id: string } }>(
    `mutation($input: ProjectCreateInput!) {
      projectCreate(input: $input) { id }
    }`,
    { input: { name } }
  );
  return data.projectCreate.id;
}

export async function createService(
  projectId: string,
  repo: string,
  branch: string = "main",
  rootDirectory: string = "apps/agent"
): Promise<{ serviceId: string; environmentId: string }> {
  // Get the default environment for this project
  const projData = await gql<{
    project: { environments: { edges: { node: { id: string } }[] } };
  }>(
    `query($id: String!) {
      project(id: $id) {
        environments { edges { node { id } } }
      }
    }`,
    { id: projectId }
  );

  const environmentId = projData.project.environments.edges[0]?.node.id;
  if (!environmentId) throw new Error("No environment found for project");

  const data = await gql<{ serviceCreate: { id: string } }>(
    `mutation($input: ServiceCreateInput!) {
      serviceCreate(input: $input) { id }
    }`,
    {
      input: {
        projectId,
        name: "agent",
        source: {
          repo,
        },
      },
    }
  );

  // Set the root directory and branch via service instance update
  await gql(
    `mutation($serviceId: String!, $environmentId: String!, $input: ServiceInstanceUpdateInput!) {
      serviceInstanceUpdate(serviceId: $serviceId, environmentId: $environmentId, input: $input)
    }`,
    {
      serviceId: data.serviceCreate.id,
      environmentId,
      input: {
        source: {
          repo,
          branch,
        },
        rootDirectory,
      },
    }
  );

  return { serviceId: data.serviceCreate.id, environmentId };
}

export async function setEnvVars(
  serviceId: string,
  environmentId: string,
  vars: Record<string, string>
): Promise<void> {
  // Railway upserts variables one at a time via variableUpsert
  for (const [name, value] of Object.entries(vars)) {
    await gql(
      `mutation($input: VariableUpsertInput!) {
        variableUpsert(input: $input)
      }`,
      {
        input: {
          projectId: "", // filled below
          serviceId,
          environmentId,
          name,
          value,
        },
      }
    );
  }
}

export async function setEnvVarsForProject(
  projectId: string,
  serviceId: string,
  environmentId: string,
  vars: Record<string, string>
): Promise<void> {
  for (const [name, value] of Object.entries(vars)) {
    await gql(
      `mutation($input: VariableUpsertInput!) {
        variableUpsert(input: $input)
      }`,
      {
        input: {
          projectId,
          serviceId,
          environmentId,
          name,
          value,
        },
      }
    );
  }
}

export async function createVolume(
  projectId: string,
  serviceId: string,
  environmentId: string,
  mountPath: string = "/data"
): Promise<string> {
  const data = await gql<{ volumeCreate: { id: string } }>(
    `mutation($input: VolumeCreateInput!) {
      volumeCreate(input: $input) { id }
    }`,
    {
      input: {
        projectId,
        serviceId,
        environmentId,
        mountPath,
      },
    }
  );
  return data.volumeCreate.id;
}

export async function createDomain(
  serviceId: string,
  environmentId: string
): Promise<string> {
  const data = await gql<{ serviceDomainCreate: { domain: string } }>(
    `mutation($input: ServiceDomainCreateInput!) {
      serviceDomainCreate(input: $input) { domain }
    }`,
    {
      input: {
        serviceId,
        environmentId,
      },
    }
  );
  return data.serviceDomainCreate.domain;
}

export async function triggerDeploy(
  serviceId: string,
  environmentId: string
): Promise<string> {
  const data = await gql<{
    serviceInstanceRedeploy: string;
  }>(
    `mutation($serviceId: String!, $environmentId: String!) {
      serviceInstanceRedeploy(serviceId: $serviceId, environmentId: $environmentId)
    }`,
    { serviceId, environmentId }
  );
  return data.serviceInstanceRedeploy;
}

export async function getDeploymentStatus(
  deploymentId: string
): Promise<{ status: string }> {
  const data = await gql<{
    deployment: { status: string };
  }>(
    `query($id: String!) {
      deployment(id: $id) { status }
    }`,
    { id: deploymentId }
  );
  return { status: data.deployment.status };
}

export async function getLatestDeployment(
  serviceId: string,
  environmentId: string
): Promise<{ id: string; status: string } | null> {
  const data = await gql<{
    deployments: { edges: { node: { id: string; status: string } }[] };
  }>(
    `query($input: DeploymentListInput!) {
      deployments(input: $input, first: 1) {
        edges { node { id status } }
      }
    }`,
    {
      input: {
        serviceId,
        environmentId,
      },
    }
  );

  const edge = data.deployments.edges[0];
  return edge ? { id: edge.node.id, status: edge.node.status } : null;
}

export async function getDeploymentLogs(
  deploymentId: string
): Promise<string[]> {
  const data = await gql<{
    deploymentLogs: { message: string }[];
  }>(
    `query($id: String!) {
      deploymentLogs(deploymentId: $id, limit: 200) { message }
    }`,
    { id: deploymentId }
  );
  return data.deploymentLogs.map((l) => l.message);
}

