 1→import { NextRequest, NextResponse } from "next/server";
 2→import {
 3→  createService,
 4→  setEnvVars,
 5→  createVolume,
 6→  createDomain,
 7→} from "@/lib/railway";
 8→
 9→interface DeployRequest {
10→  agentName: string;
11→  veniceModel: string;
12→  spendingCap: string;
13→  dailyLimit: string;
14→  telegramBotToken?: string;
15→  telegramAllowedUsers?: string;
16→}
17→
18→export async function POST(req: NextRequest) {
19→  const body: DeployRequest = await req.json();
20→
21→  if (!body.agentName) {
22→    return NextResponse.json(
23→      { error: "Missing agent name" },
24→      { status: 400 }
25→    );
26→  }
27→
28→  try {
29→    const projectId = process.env.RAILWAY_PROJECT_ID;
30→    if (!projectId) {
31→      return NextResponse.json(
32→        { error: "RAILWAY_PROJECT_ID is not configured" },
33→        { status: 500 }
34→      );
35→    }
36→
37→    // 1. Create service from GitHub repo (name = agent name for uniqueness)
38→    const repo = "builders-garden/synthesis-hack";
39→    const { serviceId, environmentId } = await createService(
40→      projectId,
41→      body.agentName,
42→      repo,
43→      "main",
44→      "apps/agent"
45→    );
46→
47→    // 2. Set env vars (bulk, single API call)
48→    const setupPassword = crypto.randomUUID().replace(/-/g, "").slice(0, 32);
49→    const envVars: Record<string, string> = {
50→      AGENT_NAME: body.agentName,
51→      SETUP_PASSWORD: setupPassword,
52→      VENICE_MODEL: body.veniceModel || "venice/llama-3.3-70b",
53→      SPENDING_CAP: body.spendingCap || "5",
54→      DAILY_LIMIT: body.dailyLimit || "10",
55→    };
56→
57→    if (body.telegramBotToken) {
58→      envVars.TELEGRAM_BOT_TOKEN = body.telegramBotToken;
59→    }
60→    if (body.telegramAllowedUsers) {
61→      envVars.TELEGRAM_ALLOWED_USERS = body.telegramAllowedUsers;
62→    }
63→
64→    await setEnvVars(projectId, serviceId, environmentId, envVars);
65→
66→    // 3. Create persistent volume
67→    await createVolume(projectId, serviceId, environmentId, "/data");
68→
69→    // 4. Generate public domain
70→    const domain = await createDomain(serviceId, environmentId);
71→
72→    // Railway auto-deploys when service is created with a linked repo + env vars set
73→
74→    return NextResponse.json({
75→      projectId,
76→      serviceId,
77→      environmentId,
78→      domain: `https://${domain}`,
79→      setupPassword,
80→      status: "deploying",
81→    });
82→  } catch (err) {
83→    const message = err instanceof Error ? err.message : "Deploy failed";
84→    console.error("Railway deploy error:", message);
85→    return NextResponse.json({ error: message }, { status: 500 });
86→  }
87→}
