  1→"use client";
  2→
  3→import { useState, useCallback } from "react";
  4→
  5→interface DeployInfo {
  6→  projectId: string;
  7→  serviceId: string;
  8→  environmentId: string;
  9→  domain: string;
 10→  setupPassword: string;
 11→}
 12→
 13→interface DeployState {
 14→  deployInfo: DeployInfo | null;
 15→  deployStatus: string | null;
 16→  walletAddress: string | null;
 17→  error: string | null;
 18→  loading: boolean;
 19→}
 20→
 21→export function useAgentDeploy() {
 22→  const [state, setState] = useState<DeployState>({
 23→    deployInfo: null,
 24→    deployStatus: null,
 25→    walletAddress: null,
 26→    error: null,
 27→    loading: false,
 28→  });
 29→
 30→  const deployAgent = useCallback(
 31→    async (config: {
 32→      agentName: string;
 33→      veniceModel: string;
 34→      spendingCap: string;
 35→      dailyLimit: string;
 36→      telegramBotToken?: string;
 37→      telegramAllowedUsers?: string;
 38→    }) => {
 39→      setState((s) => ({ ...s, loading: true, error: null }));
 40→      try {
 41→        const res = await fetch("/api/agent/deploy", {
 42→          method: "POST",
 43→          headers: { "Content-Type": "application/json" },
 44→          body: JSON.stringify(config),
 45→        });
 46→        const data = await res.json();
 47→        if (data.error) throw new Error(data.error);
 48→
 49→        const info: DeployInfo = {
 50→          projectId: data.projectId,
 51→          serviceId: data.serviceId,
 52→          environmentId: data.environmentId,
 53→          domain: data.domain,
 54→          setupPassword: data.setupPassword,
 55→        };
 56→
 57→        setState((s) => ({
 58→          ...s,
 59→          deployInfo: info,
 60→          deployStatus: "DEPLOYING",
 61→          loading: false,
 62→        }));
 63→
 64→        return info;
 65→      } catch (err) {
 66→        const message =
 67→          err instanceof Error ? err.message : "Deploy failed";
 68→        setState((s) => ({ ...s, error: message, loading: false }));
 69→        return null;
 70→      }
 71→    },
 72→    []
 73→  );
 74→
 75→  const pollDeployStatus = useCallback(
 76→    async (serviceId: string, environmentId: string) => {
 77→      setState((s) => ({ ...s, loading: true }));
 78→      const maxAttempts = 60; // ~5 minutes with 5s intervals
 79→
 80→      for (let i = 0; i < maxAttempts; i++) {
 81→        try {
 82→          const res = await fetch(
 83→            `/api/agent/deploy/status?serviceId=${serviceId}&environmentId=${environmentId}`
 84→          );
 85→          const data = await res.json();
 86→
 87→          setState((s) => ({
 88→            ...s,
 89→            deployStatus: data.status,
 90→            walletAddress: data.walletAddress || s.walletAddress,
 91→          }));
 92→
 93→          if (data.status === "SUCCESS") {
 94→            setState((s) => ({ ...s, loading: false }));
 95→            return { status: "SUCCESS", walletAddress: data.walletAddress };
 96→          }
 97→
 98→          if (data.status === "FAILED" || data.status === "CRASHED") {
 99→            setState((s) => ({
100→              ...s,
101→              error: `Deployment ${data.status.toLowerCase()}`,
102→              loading: false,
103→            }));
104→            return { status: data.status, walletAddress: null };
105→          }
106→        } catch {
107→          // retry
108→        }
109→
110→        await new Promise((r) => setTimeout(r, 5000));
111→      }
112→
113→      setState((s) => ({
114→        ...s,
115→        error: "Deployment timed out",
116→        loading: false,
117→      }));
118→      return { status: "TIMEOUT", walletAddress: null };
119→    },
120→    []
121→  );
122→
123→  const getAgentWallet = useCallback(async (agentUrl: string) => {
124→    try {
125→      const res = await fetch(`${agentUrl}/health`);
126→      const data = await res.json();
127→      if (data.walletAddress) {
128→        setState((s) => ({ ...s, walletAddress: data.walletAddress }));
129→        return data.walletAddress as string;
130→      }
131→    } catch {
132→      // Agent may not be ready yet
133→    }
134→    return null;
135→  }, []);
136→
137→  return {
138→    ...state,
139→    deployAgent,
140→    pollDeployStatus,
141→    getAgentWallet,
142→  };
143→}
144→

