38→    let walletAddress: string | null = null;
39→    if (status === "SUCCESS" && currentDeploymentId) {
40→      try {
41→        const logs = await getDeploymentLogs(currentDeploymentId);
42→        for (const line of logs) {
43→          // The init script logs: "[init]   Wallet:   0x..."
44→          const match = line.match(/Wallet:\s+(0x[a-fA-F0-9]{40})/i);
45→          if (match) {
46→            walletAddress = match[1];
47→            break;
48→          }
49→        }
50→      } catch {
51→        // Logs may not be available yet
52→      }
53→    }
54→
55→    return NextResponse.json({
56→      status,
57→      deploymentId: currentDeploymentId,
58→      walletAddress,
59→    });
60→  } catch (err) {
61→    const message = err instanceof Error ? err.message : "Status check failed";
62→    return NextResponse.json({ error: message }, { status: 500 });
63→  }
64→}
65→

  1→const RAILWAY_API = "https://backboard.railway.com/graphql/v2";
  2→
  3→function getToken(): string {
  4→  const token = process.env.RAILWAY_API_TOKEN;
  5→  if (!token) throw new Error("RAILWAY_API_TOKEN is not set");
  6→  return token;
  7→}
  8→
  9→async function gql<T>(query: string, variables?: Record<string, unknown>): Promise<T> {
 10→  const res = await fetch(RAILWAY_API, {
 11→    method: "POST",
 12→    headers: {
 13→      "Content-Type": "application/json",
 14→      Authorization: `Bearer ${getToken()}`,
 15→    },
 16→    body: JSON.stringify({ query, variables }),
 17→  });
 18→
 19→  const json = await res.json();
 20→  if (json.errors) {
 21→    throw new Error(json.errors.map((e: { message: string }) => e.message).join(", "));
 22→  }
 23→  return json.data as T;
 24→}
