154→export async function getDeploymentStatus(
155→  deploymentId: string
156→): Promise<{ status: string }> {
157→  const data = await gql<{
158→    deployment: { status: string };
159→  }>(
160→    `query($id: String!) {
161→      deployment(id: $id) { status }
162→    }`,
163→    { id: deploymentId }
164→  );
165→  return { status: data.deployment.status };
166→}
