194→export async function getDeploymentLogs(
195→  deploymentId: string
196→): Promise<string[]> {
197→  const data = await gql<{
198→    deploymentLogs: { message: string }[];
199→  }>(
200→    `query($id: String!) {
201→      deploymentLogs(deploymentId: $id, limit: 200) { message }
202→    }`,
203→    { id: deploymentId }
204→  );
205→  return data.deploymentLogs.map((l) => l.message);
