 1→import { NextRequest, NextResponse } from "next/server";
 2→import {
 3→  createService,
 4→  setEnvVars,
 5→  createVolume,
 6→  createDomain,
 7→} from "@/lib/railway";
 8→
 9→interface DeployRequest {
10→  agentName: string;
11→  veniceModel: string;
12→  spendingCap: string;
13→  dailyLimit: string;
14→  telegramBotToken?: string;
15→  telegramAllowedUsers?: string;
16→}
17→
18→export async function POST(req: NextRequest) {
19→  const body: DeployRequest = await req.json();
20→
21→  if (!body.agentName) {
22→    return NextResponse.json(
23→      { error: "Missing agent name" },
24→      { status: 400 }
25→    );
26→  }
27→
28→  try {
29→    const projectId = process.env.RAILWAY_PROJECT_ID;
30→    if (!projectId) {
31→      return NextResponse.json(
32→        { error: "RAILWAY_PROJECT_ID is not configured" },
33→        { status: 500 }
34→      );
35→    }
36→
37→    // 1. Create service from GitHub repo (name = agent name for uniqueness)
38→    const repo = "builders-garden/synthesis-hack";
39→    const { serviceId, environmentId } = await createService(
40→      projectId,
41→      body.agentName,
42→      repo,
43→      "main",
44→      "apps/agent"
45→    );
46→
47→    // 2. Set env vars (bulk, single API call)
48→    const setupPassword = crypto.randomUUID().replace(/-/g, "").slice(0, 32);
49→    const envVars: Record<string, string> = {
50→      AGENT_NAME: body.agentName,
51→      SETUP_PASSWORD: setupPassword,
52→      VENICE_MODEL: body.veniceModel || "venice/llama-3.3-70b",
53→      SPENDING_CAP: body.spendingCap || "5",
54→      DAILY_LIMIT: body.dailyLimit || "10",
55→    };
56→
57→    // Locus: pass through from server env if available (agent self-registers if missing)
58→    const locusApiKey = process.env.LOCUS_API_KEY;
59→    if (locusApiKey) {
60→      envVars.LOCUS_API_KEY = locusApiKey;
61→    }
62→
63→    // Telegram: use frontend values, fall back to server env vars, skip if neither
64→    const telegramToken = body.telegramBotToken || process.env.TELEGRAM_BOT_TOKEN;
65→    const telegramUsers = body.telegramAllowedUsers || process.env.TELEGRAM_ALLOWED_USERS;
66→    if (telegramToken) {
67→      envVars.TELEGRAM_BOT_TOKEN = telegramToken;
68→    }
69→    if (telegramUsers) {
70→      envVars.TELEGRAM_ALLOWED_USERS = telegramUsers;
71→    }
72→
73→    await setEnvVars(projectId, serviceId, environmentId, envVars);
74→
75→    // 3. Create persistent volume
76→    await createVolume(projectId, serviceId, environmentId, "/data");
77→
78→    // 4. Generate public domain
79→    const domain = await createDomain(serviceId, environmentId);
80→
81→    // Railway auto-deploys when service is created with a linked repo + env vars set
82→
83→    return NextResponse.json({
84→      projectId,
85→      serviceId,
86→      environmentId,
87→      domain: `https://${domain}`,
88→      setupPassword,
89→      status: "deploying",
90→    });
91→  } catch (err) {
92→    const message = err instanceof Error ? err.message : "Deploy failed";
93→    console.error("Railway deploy error:", message);
94→    return NextResponse.json({ error: message }, { status: 500 });
95→  }
96→}
