  2→pragma solidity ^0.8.24;
  3→
  4→import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
  5→import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
  6→import {Math} from "@openzeppelin/contracts/utils/math/Math.sol";
  7→import {IAggregatorV3} from "./interfaces/IAggregatorV3.sol";
  8→
  9→/// @title YieldVault
 10→/// @notice Per-user vault that holds wstETH on Base. The owner (human) deposits principal,
 11→///         and an agent wallet can withdraw a configurable share of accrued yield on a cooldown.
 12→///         Yield is computed via the Chainlink wstETH/stETH exchange rate oracle.
 13→///         Deployed as an EIP-1167 clone by YieldVaultFactory.
 14→contract YieldVault {
 15→    using SafeERC20 for IERC20;
 16→    using Math for uint256;
 17→
 18→    // ──────────────────────────────────────────────
 19→    //  Constants
 20→    // ──────────────────────────────────────────────
 21→
 22→    address public constant WSTETH = 0xc1CBa3fCea344f92D9239c08C0568f6F2F0ee452;
 23→    address public constant ORACLE = 0xB88BAc61a4Ca37C43a3725912B1f472c9A5bc061;
 24→    uint256 public constant ORACLE_STALENESS = 90_000; // 25 hours
 25→    uint256 public constant BPS_DENOMINATOR = 10_000;
 26→    uint256 public constant MIN_ORACLE_RATE = 0.5e18;
 27→    uint256 public constant MAX_ORACLE_RATE = 1.5e18;
 28→    uint8 public constant EXPECTED_ORACLE_DECIMALS = 18;
 29→
 30→    // ──────────────────────────────────────────────
 31→    //  State
 32→    // ──────────────────────────────────────────────
 33→
 34→    address public factory;
 35→    address public owner;
 36→
 37→    /// @notice The depositor's principal denominated in stETH (18 decimals).
 38→    ///         Yield = totalValueInStETH - principalStETH.
 39→    uint256 public principalStETH;
 40→
 41→    // Agent configuration
 42→    address public agentWallet;
 43→    uint16 public yieldShareBps;
 44→    uint32 public withdrawalFrequency;
 45→    uint256 public lastAgentWithdrawal;
 46→
 47→    // Safety
 48→    bool public paused;
 49→    bool public initialized;
 50→
 51→    // Reentrancy lock (0 = unlocked, 1 = locked). Works in clones (storage starts at 0).
 52→    uint256 private _locked;
 53→
 54→    // ──────────────────────────────────────────────
 55→    //  Events
 56→    // ──────────────────────────────────────────────
 57→
 58→    event Deposited(uint256 wstETHAmount, uint256 newPrincipalStETH);
 59→    event PrincipalWithdrawn(address indexed to, uint256 wstETHAmount);
 60→    event YieldWithdrawn(address indexed to, uint256 wstETHAmount);
 61→    event AgentWithdrawal(address indexed agent, uint256 wstETHAmount);
 62→    event SettingsUpdated(address agent, uint16 yieldShareBps, uint32 frequency);
 63→    event VaultPaused();
 64→    event VaultUnpaused();
 65→
 66→    // ──────────────────────────────────────────────
 67→    //  Errors
 68→    // ──────────────────────────────────────────────
 69→
 70→    error AlreadyInitialized();
 71→    error NotOwner();
 72→    error NotAgent();
 73→    error Reentrancy();
 74→    error VaultIsPaused();
 75→    error ZeroAmount();
 76→    error ZeroAddress();
 77→    error ExceedsPrincipal();
 78→    error ExceedsYield();
 79→    error ExceedsBudget();
 80→    error CooldownNotElapsed();
 81→    error StaleOracle();
 82→    error InvalidOracleAnswer();
 83→    error OraclePriceOutOfBounds();
 84→    error InvalidOracleDecimals();
 85→    error InvalidYieldShare();
 86→    error NothingToWithdraw();
 87→
 88→    // ──────────────────────────────────────────────
 89→    //  Modifiers
 90→    // ──────────────────────────────────────────────
 91→
 92→    modifier onlyOwner() {
 93→        if (msg.sender != owner) revert NotOwner();
 94→        _;
 95→    }
 96→
 97→    modifier whenNotPaused() {
 98→        if (paused) revert VaultIsPaused();
 99→        if (IYieldVaultFactory(factory).paused()) revert VaultIsPaused();
100→        _;
101→    }
102→
103→    modifier nonReentrant() {
104→        if (_locked == 1) revert Reentrancy();
105→        _locked = 1;
106→        _;
107→        _locked = 0;
108→    }
109→
110→    // ──────────────────────────────────────────────
111→    //  Initialization (called once by factory)
112→    // ──────────────────────────────────────────────
113→
114→    function initialize(
115→        address _factory,
116→        address _owner,
117→        address _agent,
118→        uint16 _yieldShareBps,
119→        uint32 _frequency
120→    ) external {
121→        if (initialized) revert AlreadyInitialized();
122→        if (_owner == address(0)) revert ZeroAddress();
123→        if (_agent == address(0)) revert ZeroAddress();
124→        if (_yieldShareBps > BPS_DENOMINATOR) revert InvalidYieldShare();
125→
126→        initialized = true;
127→        factory = _factory;
128→        owner = _owner;
129→        agentWallet = _agent;
130→        yieldShareBps = _yieldShareBps;
131→        withdrawalFrequency = _frequency;
132→    }
133→
134→    // ──────────────────────────────────────────────
135→    //  Owner (human) functions
136→    // ──────────────────────────────────────────────
137→
138→    /// @notice Deposit wstETH into the vault. Caller must have approved this contract.
139→    function deposit(uint256 wstETHAmount) external onlyOwner whenNotPaused nonReentrant {
140→        if (wstETHAmount == 0) revert ZeroAmount();
141→
142→        uint256 currentRate = _getCurrentRate();
143→        principalStETH += wstETHAmount.mulDiv(currentRate, 1e18);
144→
145→        IERC20(WSTETH).safeTransferFrom(msg.sender, address(this), wstETHAmount);
146→
147→        emit Deposited(wstETHAmount, principalStETH);
148→    }
149→
150→    /// @notice Withdraw wstETH that belongs to principal (does not touch yield).
151→    function withdrawPrincipal(uint256 wstETHAmount) external onlyOwner whenNotPaused nonReentrant {
152→        if (wstETHAmount == 0) revert ZeroAmount();
153→
154→        uint256 currentRate = _getCurrentRate();
155→        uint256 principalInWstETH = principalStETH.mulDiv(1e18, currentRate);
156→        if (wstETHAmount > principalInWstETH) revert ExceedsPrincipal();
157→
158→        principalStETH -= wstETHAmount.mulDiv(currentRate, 1e18);
159→
160→        IERC20(WSTETH).safeTransfer(owner, wstETHAmount);
161→
162→        emit PrincipalWithdrawn(owner, wstETHAmount);
163→    }
164→
165→    /// @notice Withdraw accrued yield (owner has full access to yield).
166→    function withdrawYield(uint256 wstETHAmount) external onlyOwner whenNotPaused nonReentrant {
167→        if (wstETHAmount == 0) revert ZeroAmount();
168→
169→        uint256 yieldWstETH = getAccruedYieldInWstETH();
170→        if (wstETHAmount > yieldWstETH) revert ExceedsYield();
171→
172→        // principalStETH unchanged — only yield leaves
173→        IERC20(WSTETH).safeTransfer(owner, wstETHAmount);
174→
175→        emit YieldWithdrawn(owner, wstETHAmount);
176→    }
177→
178→    /// @notice Emergency exit: withdraw principal + accrued yield. Works even when paused.
179→    ///         Force-fed tokens (direct transfers) are left in the contract.
180→    function exit() external onlyOwner nonReentrant {
181→        uint256 currentRate = _getCurrentRate();
182→        uint256 principalWstETH = principalStETH.mulDiv(1e18, currentRate);
183→        uint256 yieldWstETH = getAccruedYieldInWstETH();
184→        uint256 totalOwed = principalWstETH + yieldWstETH;
185→        if (totalOwed == 0) revert NothingToWithdraw();
186→
187→        principalStETH = 0;
188→
189→        IERC20(WSTETH).safeTransfer(owner, totalOwed);
190→
191→        emit PrincipalWithdrawn(owner, totalOwed);
192→    }
193→
194→    /// @notice Update agent wallet, yield share, and withdrawal frequency.
195→    function updateSettings(address _agent, uint16 _yieldShareBps, uint32 _frequency) external onlyOwner {
196→        if (_agent == address(0)) revert ZeroAddress();
197→        if (_yieldShareBps > BPS_DENOMINATOR) revert InvalidYieldShare();
198→
199→        address oldAgent = agentWallet;
200→        agentWallet = _agent;
201→        yieldShareBps = _yieldShareBps;
202→        withdrawalFrequency = _frequency;
203→
204→        // Sync factory mapping if agent changed.
205→        if (_agent != oldAgent) {
206→            IYieldVaultFactory(factory).onAgentUpdated(oldAgent, _agent);
207→        }
208→
209→        emit SettingsUpdated(_agent, _yieldShareBps, _frequency);
210→    }
211→
212→    function pause() external onlyOwner {
213→        paused = true;
214→        emit VaultPaused();
215→    }
216→
217→    function unpause() external onlyOwner {
218→        paused = false;
219→        emit VaultUnpaused();
220→    }
221→
222→    // ──────────────────────────────────────────────
223→    //  Agent functions
224→    // ──────────────────────────────────────────────
225→
226→    /// @notice Agent withdraws up to `yieldShareBps` percent of accrued yield.
227→    ///         Subject to `withdrawalFrequency` cooldown between calls.
228→    function agentWithdraw(uint256 wstETHAmount) external whenNotPaused nonReentrant {
229→        if (msg.sender != agentWallet) revert NotAgent();
230→        if (wstETHAmount == 0) revert ZeroAmount();
231→        if (block.timestamp < lastAgentWithdrawal + uint256(withdrawalFrequency)) {
232→            revert CooldownNotElapsed();
233→        }
234→
235→        uint256 yieldWstETH = getAccruedYieldInWstETH();
236→        uint256 budget = yieldWstETH.mulDiv(yieldShareBps, BPS_DENOMINATOR);
237→        if (wstETHAmount > budget) revert ExceedsBudget();
238→
239→        lastAgentWithdrawal = block.timestamp;
240→
241→        // principalStETH unchanged — agent only touches yield
242→        IERC20(WSTETH).safeTransfer(agentWallet, wstETHAmount);
243→
244→        emit AgentWithdrawal(agentWallet, wstETHAmount);
245→    }
246→
247→    // ──────────────────────────────────────────────
248→    //  View functions
249→    // ──────────────────────────────────────────────
250→
251→    /// @notice Returns accrued yield denominated in wstETH.
252→    function getAccruedYieldInWstETH() public view returns (uint256) {
253→        uint256 balance = IERC20(WSTETH).balanceOf(address(this));
254→        if (balance == 0) return 0;
255→
256→        uint256 currentRate = _getCurrentRate();
257→        uint256 totalValueStETH = balance.mulDiv(currentRate, 1e18);
258→
259→        if (totalValueStETH <= principalStETH) return 0;
260→
261→        uint256 yieldStETH = totalValueStETH - principalStETH;
262→        return yieldStETH.mulDiv(1e18, currentRate);
263→    }
264→
265→    /// @notice Returns the wstETH amount the agent can withdraw right now.
266→    ///         Returns 0 if the cooldown has not elapsed.
267→    function getAgentBudget() external view returns (uint256) {
268→        if (block.timestamp < lastAgentWithdrawal + uint256(withdrawalFrequency)) return 0;
269→
270→        uint256 yieldWstETH = getAccruedYieldInWstETH();
271→        return yieldWstETH.mulDiv(yieldShareBps, BPS_DENOMINATOR);
272→    }
273→
274→    /// @notice Total value held in the vault, denominated in stETH.
275→    function getTotalValueInStETH() external view returns (uint256) {
276→        uint256 balance = IERC20(WSTETH).balanceOf(address(this));
277→        if (balance == 0) return 0;
278→        uint256 currentRate = _getCurrentRate();
279→        return balance.mulDiv(currentRate, 1e18);
280→    }
281→
282→    /// @notice Current wstETH/stETH exchange rate from Chainlink (18 decimals).
283→    function getCurrentRate() external view returns (uint256) {
284→        return _getCurrentRate();
285→    }
286→
287→    // ──────────────────────────────────────────────
288→    //  Internal
289→    // ──────────────────────────────────────────────
290→
291→    function _getCurrentRate() internal view returns (uint256) {
292→        if (IAggregatorV3(ORACLE).decimals() != EXPECTED_ORACLE_DECIMALS) revert InvalidOracleDecimals();
293→        (uint80 roundId, int256 answer,, uint256 updatedAt, uint80 answeredInRound) =
294→            IAggregatorV3(ORACLE).latestRoundData();
295→        if (answer <= 0) revert InvalidOracleAnswer();
296→        if (answeredInRound < roundId) revert InvalidOracleAnswer();
297→        if (block.timestamp - updatedAt > ORACLE_STALENESS) revert StaleOracle();
298→        uint256 rate = uint256(answer);
299→        if (rate < MIN_ORACLE_RATE || rate > MAX_ORACLE_RATE) revert OraclePriceOutOfBounds();
300→        return rate;
301→    }
302→}
303→
304→/// @dev Minimal interface the vault uses to interact with the factory.
305→interface IYieldVaultFactory {
306→    function paused() external view returns (bool);
307→    function onAgentUpdated(address oldAgent, address newAgent) external;
308→}
