  1→// SPDX-License-Identifier: MIT
  2→pragma solidity ^0.8.24;
  3→
  4→import {Clones} from "@openzeppelin/contracts/proxy/Clones.sol";
  5→import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
  6→import {YieldVault} from "./YieldVault.sol";
  7→
  8→/// @title YieldVaultFactory
  9→/// @notice Deploys EIP-1167 minimal-proxy YieldVault instances, one per user/team.
 10→///         The factory owner (protocol admin) can pause all vaults globally.
 11→contract YieldVaultFactory is Ownable {
 12→    using Clones for address;
 13→
 14→    // ──────────────────────────────────────────────
 15→    //  State
 16→    // ──────────────────────────────────────────────
 17→
 18→    address public immutable implementation;
 19→    bool public paused;
 20→    uint256 public constant MAX_VAULTS_PER_AGENT = 50;
 21→
 22→    mapping(address => address) public vaults;
 23→    address[] public allVaults;
 24→
 25→    /// @notice agent address → list of vaults where it is the agent.
 26→    mapping(address => address[]) internal _agentVaults;
 27→
 28→    // ──────────────────────────────────────────────
 29→    //  Events
 30→    // ──────────────────────────────────────────────
 31→
 32→    event VaultCreated(address indexed owner, address indexed vault, address agent);
 33→    event AgentUpdated(address indexed vault, address indexed oldAgent, address indexed newAgent);
 34→    event FactoryPaused();
 35→    event FactoryUnpaused();
 36→
 37→    // ──────────────────────────────────────────────
 38→    //  Errors
 39→    // ──────────────────────────────────────────────
 40→
 41→    error VaultAlreadyExists();
 42→    error FactoryIsPaused();
 43→    error ZeroAddress();
 44→    error InvalidYieldShare();
 45→    error NotVault();
 46→    error AgentVaultLimitReached();
 47→
 48→    // ──────────────────────────────────────────────
 49→    //  Constructor
 50→    // ──────────────────────────────────────────────
 51→
 52→    constructor(address _implementation) Ownable(msg.sender) {
 53→        implementation = _implementation;
 54→    }
 55→
 56→    // ──────────────────────────────────────────────
 57→    //  Vault creation
 58→    // ──────────────────────────────────────────────
 59→
 60→    /// @notice Deploy a new YieldVault clone for the caller.
 61→    /// @param agent         Address of the agent wallet that can withdraw yield.
 62→    /// @param yieldShareBps Percentage of accrued yield the agent may withdraw (basis points, 0-10 000).
 63→    /// @param frequency     Minimum seconds between agent withdrawals.
 64→    /// @return vault        Address of the newly created vault.
 65→    function createVault(
 66→        address agent,
 67→        uint16 yieldShareBps,
 68→        uint32 frequency
 69→    ) external returns (address vault) {
 70→        if (paused) revert FactoryIsPaused();
 71→        if (vaults[msg.sender] != address(0)) revert VaultAlreadyExists();
 72→        if (agent == address(0)) revert ZeroAddress();
 73→        if (yieldShareBps > 10_000) revert InvalidYieldShare();
 74→        if (_agentVaults[agent].length >= MAX_VAULTS_PER_AGENT) revert AgentVaultLimitReached();
 75→
 76→        vault = implementation.clone();
 77→        YieldVault(vault).initialize(address(this), msg.sender, agent, yieldShareBps, frequency);
 78→
 79→        vaults[msg.sender] = vault;
 80→        allVaults.push(vault);
 81→        _agentVaults[agent].push(vault);
 82→
 83→        emit VaultCreated(msg.sender, vault, agent);
 84→    }
 85→
 86→    // ──────────────────────────────────────────────
 87→    //  Admin
 88→    // ──────────────────────────────────────────────
 89→
 90→    function pause() external onlyOwner {
 91→        paused = true;
 92→        emit FactoryPaused();
 93→    }
 94→
 95→    function unpause() external onlyOwner {
 96→        paused = false;
 97→        emit FactoryUnpaused();
 98→    }
 99→
100→    // ──────────────────────────────────────────────
101→    //  Agent mapping sync (called by vaults)
102→    // ──────────────────────────────────────────────
103→
104→    /// @notice Called by a vault when its agent is changed via updateSettings.
105→    function onAgentUpdated(address oldAgent, address newAgent) external {
106→        // Only registered vaults may call this.
107→        // We check that msg.sender is a known vault by looking up its owner.
108→        address vaultOwner = YieldVault(msg.sender).owner();
109→        if (vaults[vaultOwner] != msg.sender) revert NotVault();
110→
111→        // Remove vault from old agent's list.
112→        _removeAgentVault(oldAgent, msg.sender);
113→
114→        // Add vault to new agent's list.
115→        if (_agentVaults[newAgent].length >= MAX_VAULTS_PER_AGENT) revert AgentVaultLimitReached();
116→        _agentVaults[newAgent].push(msg.sender);
117→
118→        emit AgentUpdated(msg.sender, oldAgent, newAgent);
119→    }
120→
121→    // ──────────────────────────────────────────────
122→    //  Views
123→    // ──────────────────────────────────────────────
124→
125→    function totalVaults() external view returns (uint256) {
126→        return allVaults.length;
127→    }
128→
129→    /// @notice Returns all vaults where `agent` is the current agent wallet.
130→    function getAgentVaults(address agent) external view returns (address[] memory) {
131→        return _agentVaults[agent];
132→    }
133→
134→    // ──────────────────────────────────────────────
135→    //  Internal
136→    // ──────────────────────────────────────────────
137→
138→    function _removeAgentVault(address agent, address vault) internal {
139→        address[] storage arr = _agentVaults[agent];
140→        uint256 len = arr.length;
141→        for (uint256 i = 0; i < len; i++) {
142→            if (arr[i] == vault) {
143→                arr[i] = arr[len - 1];
144→                arr.pop();
145→                return;
146→            }
147→        }
148→    }
149→}
