 1→import { NextRequest, NextResponse } from "next/server";
 2→import {
 3→  getLatestDeployment,
 4→  getDeploymentStatus,
 5→  getDeploymentLogs,
 6→} from "@/lib/railway";
 7→
 8→export async function GET(req: NextRequest) {
 9→  const serviceId = req.nextUrl.searchParams.get("serviceId");
10→  const environmentId = req.nextUrl.searchParams.get("environmentId");
11→  const deploymentId = req.nextUrl.searchParams.get("deploymentId");
12→
13→  const projectId = process.env.RAILWAY_PROJECT_ID;
14→  if (!projectId || !serviceId || !environmentId) {
15→    return NextResponse.json(
16→      { error: "Missing projectId, serviceId, or environmentId" },
17→      { status: 400 }
18→    );
19→  }
20→
21→  try {
22→    let status: string;
23→    let currentDeploymentId = deploymentId;
24→
25→    if (currentDeploymentId) {
26→      const result = await getDeploymentStatus(currentDeploymentId);
27→      status = result.status;
28→    } else {
29→      const latest = await getLatestDeployment(projectId, serviceId, environmentId);
30→      if (!latest) {
31→        return NextResponse.json({ status: "WAITING", deploymentId: null });
32→      }
33→      status = latest.status;
34→      currentDeploymentId = latest.id;
35→    }
36→
37→    // Try to extract wallet address from logs if deployment is running
38→    let walletAddress: string | null = null;
39→    if (status === "SUCCESS" && currentDeploymentId) {
40→      try {
41→        const logs = await getDeploymentLogs(currentDeploymentId);
42→        for (const line of logs) {
43→          // The init script logs: "[init]   Wallet:   0x..."
44→          const match = line.match(/Wallet:\s+(0x[a-fA-F0-9]{40})/i);
45→          if (match) {
46→            walletAddress = match[1];
47→            break;
48→          }
49→        }
50→      } catch {
51→        // Logs may not be available yet
52→      }
53→    }
54→
55→    return NextResponse.json({
56→      status,
57→      deploymentId: currentDeploymentId,
58→      walletAddress,
59→    });
60→  } catch (err) {
61→    const message = err instanceof Error ? err.message : "Status check failed";
62→    return NextResponse.json({ error: message }, { status: 500 });
63→  }
64→}
