  1→import express from "express";
  2→import { spawn, type ChildProcess } from "child_process";
  3→import { writeFileSync, mkdirSync, existsSync } from "fs";
  4→import { join } from "path";
  5→
  6→const app = express();
  7→app.use(express.json());
  8→
  9→const PORT = parseInt(process.env.PORT || "3001", 10);
 10→const AGENTS_DIR = process.env.AGENTS_DIR || "/tmp/agents";
 11→
 12→interface AgentInstance {
 13→  name: string;
 14→  process: ChildProcess | null;
 15→  config: Record<string, unknown>;
 16→  status: "starting" | "running" | "stopped" | "error";
 17→  locusApiKey: string;
 18→  walletAddress: string;
 19→  createdAt: string;
 20→}
 21→
 22→const agents = new Map<string, AgentInstance>();
 23→
 24→// Health check
 25→app.get("/health", (_req, res) => {
 26→  res.json({ ok: true, agents: agents.size });
 27→});
 28→
 29→// List agents
 30→app.get("/agents", (_req, res) => {
 31→  const list = Array.from(agents.values()).map((a) => ({
 32→    name: a.name,
 33→    status: a.status,
 34→    walletAddress: a.walletAddress,
 35→    createdAt: a.createdAt,
 36→  }));
 37→  res.json(list);
 38→});
 39→
 40→// Get agent status
 41→app.get("/agents/:name", (req, res) => {
 42→  const agent = agents.get(req.params.name);
 43→  if (!agent) {
 44→    res.status(404).json({ error: "Agent not found" });
 45→    return;
 46→  }
 47→  res.json({
 48→    name: agent.name,
 49→    status: agent.status,
 50→    walletAddress: agent.walletAddress,
 51→    createdAt: agent.createdAt,
 52→  });
 53→});
 54→
 55→// Deploy a new agent
 56→app.post("/agents/deploy", async (req, res) => {
 57→  const {
 58→    agentName,
 59→    veniceModel,
 60→    locusApiKey,
 61→    ownerAddress,
 62→    ownerPrivateKey,
 63→    spendingCap,
 64→    dailyLimit,
 65→  } = req.body;
 66→
 67→  if (!agentName || !locusApiKey) {
 68→    res.status(400).json({ error: "agentName and locusApiKey are required" });
 69→    return;
 70→  }
 71→
 72→  if (agents.has(agentName)) {
 73→    res.status(409).json({ error: "Agent already exists" });
 74→    return;
 75→  }
 76→
 77→  try {
 78→    // Create agent workspace
 79→    const workspaceDir = join(AGENTS_DIR, agentName);
 80→    const skillsDir = join(workspaceDir, "skills", "locus-payments");
 81→    const configDir = join(workspaceDir, ".config", "locus");
 82→
 83→    mkdirSync(skillsDir, { recursive: true });
 84→    mkdirSync(configDir, { recursive: true });
 85→
 86→    // Write OpenClaw config
 87→    const openclawConfig = {
 88→      agents: {
 89→        defaults: { workspace: workspaceDir },
 90→        list: [{ id: agentName, default: true }],
 91→      },
 92→      providers: {
 93→        venice: {
 94→          type: "openai-compatible",
 95→          baseUrl: "https://api.venice.ai/api/v1",
 96→        },
 97→      },
 98→      models: {
 99→        default: veniceModel || "venice/llama-3.3-70b",
100→      },
101→    };
102→
103→    writeFileSync(
104→      join(workspaceDir, "openclaw.json"),
105→      JSON.stringify(openclawConfig, null, 2)
106→    );
107→
108→    // Write Locus credentials
109→    writeFileSync(
110→      join(configDir, "credentials.json"),
111→      JSON.stringify({
112→        api_key: locusApiKey,
113→        api_base: "https://beta-api.paywithlocus.com/api",
114→      })
115→    );
116→
117→    // Write Locus payment skill
118→    const locusSkill = `---
119→name: locus_payments
120→description: >
121→  Manage payments and API calls through Locus wallet on Base.
122→  Use this to check balance, send USDC, and call wrapped APIs.
123→version: 1.0.0
124→requires:
125→  env: ["LOCUS_API_KEY"]
126→---
127→
128→# Locus Payments Skill
129→
130→You have a Locus wallet on Base with USDC. Use it for all payments.
131→
132→## Available Actions
133→
134→### Check Balance
135→\`\`\`bash
136→curl -s https://beta-api.paywithlocus.com/api/pay/balance \\
137→  -H "Authorization: Bearer $LOCUS_API_KEY"
138→\`\`\`
139→
140→### Send USDC
141→\`\`\`bash
142→curl -s -X POST https://beta-api.paywithlocus.com/api/pay/send \\
143→  -H "Authorization: Bearer $LOCUS_API_KEY" \\
144→  -H "Content-Type: application/json" \\
145→  -d '{"to": "0xADDRESS", "amount": "1.00", "memo": "reason"}'
146→\`\`\`
147→
148→### Call Wrapped APIs (pay-per-use)
149→\`\`\`bash
150→curl -s -X POST https://beta-api.paywithlocus.com/api/wrapped/{provider}/{endpoint} \\
151→  -H "Authorization: Bearer $LOCUS_API_KEY" \\
152→  -H "Content-Type: application/json" \\
153→  -d '{"your": "payload"}'
154→\`\`\`
155→
156→Available wrapped providers: openai, gemini, firecrawl, exa, resend.
157→
158→## Spending Controls
159→- Per-transaction cap: ${spendingCap || "5"} USDC
160→- Daily limit: ${dailyLimit || "10"} USDC
161→
162→## Rules
163→- Always check balance before large transactions
164→- Log the reason for every payment via the memo field
165→- Never exceed spending controls
166→`;
167→
168→    writeFileSync(join(skillsDir, "SKILL.md"), locusSkill);
169→
170→    // Write bootstrap skill to acquire Venice API key
171→    const bootstrapSkillDir = join(workspaceDir, "skills", "bootstrap");
172→    mkdirSync(bootstrapSkillDir, { recursive: true });
173→
174→    const bootstrapSkill = `---
175→name: bootstrap
176→description: >
177→  On first run, acquire a Venice AI API key using Locus wallet funds,
178→  then configure Venice as the inference provider.
179→version: 1.0.0
180→requires:
181→  env: ["LOCUS_API_KEY"]
182→---
183→
184→# Bootstrap Skill
185→
186→On first activation, perform these steps in order:
187→
188→1. Check your Locus wallet balance to confirm funds are available.
189→2. Visit https://venice.ai and create an API key for Venice AI inference.
190→   - Use the Locus wallet to pay if Venice offers a paid API tier.
191→   - Or use the Locus wrapped OpenAI/Gemini APIs as a fallback inference provider.
192→3. Once you have the Venice API key, store it and use it for all future inference calls.
193→4. Confirm you are operational by sending a test message.
194→5. Report status via the Locus feedback endpoint:
195→   \`\`\`bash
196→   curl -s -X POST https://beta-api.paywithlocus.com/api/feedback \\
197→     -H "Authorization: Bearer $LOCUS_API_KEY" \\
198→     -H "Content-Type: application/json" \\
199→     -d '{"source": "heartbeat", "message": "Agent ${agentName} bootstrapped successfully"}'
200→   \`\`\`
201→`;
202→
203→    writeFileSync(join(bootstrapSkillDir, "SKILL.md"), bootstrapSkill);
204→
205→    // Start OpenClaw gateway as child process
206→    const env = {
207→      ...process.env,
208→      LOCUS_API_KEY: locusApiKey,
209→      LOCUS_WALLET_ADDRESS: ownerAddress,
210→      LOCUS_PRIVATE_KEY: ownerPrivateKey,
211→      OPENCLAW_HOME: workspaceDir,
212→    };
213→
214→    const child = spawn(
215→      "npx",
216→      [
217→        "openclaw",
218→        "gateway",
219→        "--config",
220→        join(workspaceDir, "openclaw.json"),
221→        "--verbose",
222→      ],
223→      {
224→        env,
225→        cwd: workspaceDir,
226→        stdio: ["ignore", "pipe", "pipe"],
227→      }
228→    );
229→
230→    const instance: AgentInstance = {
231→      name: agentName,
232→      process: child,
233→      config: openclawConfig,
234→      status: "starting",
235→      locusApiKey,
236→      walletAddress: ownerAddress,
237→      createdAt: new Date().toISOString(),
238→    };
239→
240→    child.stdout?.on("data", (data: Buffer) => {
241→      console.log(`[${agentName}] ${data.toString().trim()}`);
242→      if (instance.status === "starting") {
243→        instance.status = "running";
244→      }
245→    });
246→
247→    child.stderr?.on("data", (data: Buffer) => {
248→      console.error(`[${agentName}] ${data.toString().trim()}`);
249→    });
250→
251→    child.on("exit", (code) => {
252→      console.log(`[${agentName}] exited with code ${code}`);
253→      instance.status = code === 0 ? "stopped" : "error";
254→      instance.process = null;
255→    });
256→
257→    agents.set(agentName, instance);
258→
259→    // Mark as running after a short delay
260→    setTimeout(() => {
261→      if (instance.status === "starting") {
262→        instance.status = "running";
263→      }
264→    }, 5000);
265→
266→    res.json({
267→      agentId: agentName,
268→      walletAddress: ownerAddress,
269→      status: "starting",
270→      workspace: workspaceDir,
271→    });
272→  } catch (err) {
273→    const message = err instanceof Error ? err.message : "Deploy failed";
274→    res.status(500).json({ error: message });
275→  }
276→});
277→
278→// Stop an agent
279→app.post("/agents/:name/stop", (req, res) => {
280→  const agent = agents.get(req.params.name);
281→  if (!agent) {
282→    res.status(404).json({ error: "Agent not found" });
283→    return;
284→  }
285→
286→  if (agent.process) {
287→    agent.process.kill("SIGTERM");
288→    agent.status = "stopped";
289→  }
290→
291→  res.json({ name: agent.name, status: "stopped" });
292→});
293→
294→app.listen(PORT, () => {
295→  console.log(`Agent runtime listening on port ${PORT}`);
296→  if (!existsSync(AGENTS_DIR)) {
297→    mkdirSync(AGENTS_DIR, { recursive: true });
298→  }
299→});
